module alu
(
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output carry,
    output negative,
    output overflow,
    output flag
);
    parameter ADD = 6'b100000;
    parameter ADDU = 6'b100001;
    parameter SUB = 6'b100010;
    parameter SUBU = 6'b100011;
    parameter AND = 6'b100100;
    parameter OR = 6'b100101;
    parameter XOR = 6'b100110;
    parameter NOR = 6'b100111;
    parameter SLT = 6'b101010;
    parameter SLTU = 6'b101011;
    parameter SLL = 6'b000000;
    parameter SRL = 6'b000010;
    parameter SRA = 6'b000011;
    parameter SLLV = 6'b000100;
    parameter SRLV = 6'b000110;
    parameter SRAV = 6'b000111;
    parameter LUI = 6'b001111;
    wire signed [31:0] a_signed = a;
    wire signed [31:0] b_signed = b;
    reg [31:0] res;
    reg [0:0] carry_flag;
    reg [0:0] overflow_flag;
    reg [0:0] zero_flag;
    reg [0:0] negative_flag;
    reg [0:0] flag_internal;
    assign r = res;
    assign zero = |res;
    assign carry = carry_flag;
    assign negative = negative_flag;
    assign overflow = overflow_flag;
    assign flag = flag_internal;
    always @(*) begin
        case (aluc)
            ADD: {overflow_flag, res} = a_signed + b_signed;
            ADDU: {carry_flag, res} = a + b;
            SUB: {overflow_flag, res} = a_signed - b_signed;
            SUBU: {carry_flag, res} = a - b;
            AND: res = a & b;
            OR: res = a | b;
            XOR: res = a ^ b;
            NOR: res = ~(a | b);
            SLT: begin
                {overflow_flag, res} = a_signed + b_signed;
                flag_internal = res[31];
            end
            SLTU: begin
                {carry_flag, res} = a + b;
                flag_internal = carry_flag;
            end
            SLL: res = b << a[4:0];
            SRL: res = b >> a[4:0];
            SRA: res = b_signed >>> a[4:0];
            SLLV: res = b << a[4:0];
            SRLV: res = b >> a[4:0];
            SRAV: res = b_signed >>> a[4:0];
            LUI: res = {b[15:0], 16'b0};
            default: res = 32'b0;
        endcase
    end
endmodule
